class Solution:
    def knightTour(self, board):
        size = len(board)
        for i in range(size):
            for j in range(size):
                if board[i][j] > 0:
                    # Skip occupied cells
                    continue
                board[i][j] = 1
                if self.dfs(board, i, j):
                    return True
                board[i][j] = 0
        return False

    def dfs(self, board, i, j):
        size = len(board)
        for dx, dy in [(-1, -2), (-1, 2), (1, -2), (1, 2), (-2, -1), (-2, 1), (2, -1), (2, 1)]:
            nx, ny = i + dx, j + dy
            if nx < 0 or ny < 0 or nx >= size or ny >= size or board[nx][ny] > 0:
                continue
            board[nx][ny] = 1
            if self.dfs(board, nx, ny):
                return True
            board[nx][ny] = 0
        return False

        return True

