bool knightTour(vector<vector<int>>& board){
    int size = board.size();
    for (int i = 0; i < size; i++) {
        for (int j = 0; j < size; j++) {
            if (board[i][j] > 0) {
                // Skip occupied cells
                continue;
            }
            board[i][j] = 1;
            if (dfs(board, i, j)) {
                return true;
            }
            board[i][j] = 0;
        }
    }
    return false;

    bool dfs(vector<vector<int>>& board, int i, int j){
        int size = board.size();
        for (int dx = -1; dx <= 1; dx++) {
            for (int dy = -2; dy <= 2; dy++) {
                if (dx == 0 && dy == 0) continue;
                int nx = i + dx, ny = j + dy;
                if (nx < 0 || ny < 0 || nx >= size || ny >= size || board[nx][ny] > 0) {
                    continue;
                }
                board[nx][ny] = 1;
                if (dfs(board, nx, ny)) {
                    return true;
                }
                board[nx][ny] = 0;
            }
        }
        return false;
    }
}
